import { CoverView, IconButton, usePanelsContext } from "@portugal/ui";
import { useMatchRoute, useNavigate } from "@tanstack/react-router";
import { SquareArrowOutUpRight, X } from "lucide-react";
import type { ReactNode } from "react";

export function DetailPanelCloseButton({ panelType }: { panelType: string }) {
	const { removePanel } = usePanelsContext();
	return (
		<IconButton
			icon={X}
			aria-label="Close panel"
			onClick={() => removePanel(panelType)}
		/>
	);
}

/** Navigation targets for “open as full page” from a detail panel. */
export type DetailPanelFullPageTarget =
	| { to: "/plots/$plotId"; params: { plotId: string } }
	| { to: "/plots/profiles/$profileId"; params: { profileId: string } };

function useShowOpenFullPageAction(
	fullPageTarget: DetailPanelFullPageTarget | undefined,
): boolean {
	const matchRoute = useMatchRoute();
	if (!fullPageTarget) {
		return false;
	}
	const matched = matchRoute({
		to: fullPageTarget.to,
		params: fullPageTarget.params,
	});
	return !matched;
}

function OpenFullPageButton({
	target,
}: {
	target: DetailPanelFullPageTarget;
}) {
	const navigate = useNavigate();
	const show = useShowOpenFullPageAction(target);
	if (!show) {
		return null;
	}
	return (
		<IconButton
			icon={SquareArrowOutUpRight}
			aria-label="Open full page"
			onClick={() => {
				void navigate({
					to: target.to,
					params: target.params,
				});
			}}
		/>
	);
}

export function DetailPanelShell({
	title,
	panelType,
	children,
	fullPageTarget,
	showCloseButton = true,
}: {
	title: string;
	panelType: string;
	children: ReactNode;
	/** When set and the current route is not already this target, shows the primary chrome action. */
	fullPageTarget?: DetailPanelFullPageTarget;
	showCloseButton?: boolean;
}) {
	return (
		<CoverView
			className="h-full min-h-0"
			colorScheme="background"
			title={title}
			primaryAction={
				fullPageTarget ? <OpenFullPageButton target={fullPageTarget} /> : undefined
			}
			secondaryAction={
				showCloseButton ? (
					<DetailPanelCloseButton panelType={panelType} />
				) : undefined
			}
			contentClassName="space-y-4 pr-1 text-sm"
		>
			{children}
		</CoverView>
	);
}

